SELECT COUNT(*) 
FROM issue_contributors 
WHERE contributor_id = 0;

SELECT component_id, COUNT(issue_id) AS issue_count
FROM issue_components
GROUP BY component_id;

SELECT contributor_id, COUNT(issue_id) AS issues_count
FROM issue_contributors
GROUP BY contributor_id;

SELECT COUNT(contributor_id) AS total_contributors
FROM issue_contributors
WHERE issue_id = 1;

SELECT contributor_name
FROM contributors
WHERE contributor_id IN (SELECT contributor_id FROM issue_contributors);
